3	export type Item = { type: string };
4	
5	export type QuoteInput = {
6	  items: Item[];
7	  customerYears: number;
8	  previousContracts: number;
9	};
10	
11	const PROCESSING_FEE = 5;
12	const RUNE_BLOCK_OF_THREE_PREMIUM = 60;
13	
14	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	function basePremiumFor(item: Item): number {
24	  return BASE_PREMIUM_BY_TYPE[item.type];
25	}
26	
27	function isBlockOfThreeRunes(items: Item[]): boolean {
28	  return items.length === 3 && items.every((item) => item.type === "rune");
29	}
30	
31	export function quote(input: QuoteInput): number {
32	  if (isBlockOfThreeRunes(input.items)) {
33	    return RUNE_BLOCK_OF_THREE_PREMIUM + PROCESSING_FEE;
34	  }
35	  const itemsBasePremium = input.items.reduce(
36	    (sum, item) => sum + basePremiumFor(item),
37	    0,
38	  );
39	  return itemsBasePremium + PROCESSING_FEE;
40	}
41

